// The subset of the wallet World's dialogs need — mirrors WalletMsg minus the `type` discriminant.
// `exclusives` wasn't needed until the Lootbox/Marketplace conversion — kept here (not a separate
// getter) since it's cheap to carry and Shop simply doesn't read it.
export interface WorldWallet {
  coins: number;
  owned: string[];
  hat: string | null; skin: string | null; trail: string | null; title: string | null;
  song: string | null; car: string | null; boat: string | null; pet: string | null;
  balltrail: string | null; goalcelebr: string | null; carcolor: string | null;
  exclusives: { id: string; serial: number; instanceId: number }[];
  bets: { side: Side; amount: number; odds: number }[];
  nextSpinAt: number;
  bonusSpins: number;
  xp: number;
}
// Live-betting section state for World's shop dialog (mirrors main.ts's syncBetSection() inputs).
export interface WorldBetInfo {
  leftName: string; rightName: string;
  oddsLeft: number | null; oddsRight: number | null;
  amount: number; min: number; max: number;
  affordable: boolean;
  mine: { side: Side; amount: number; odds: number }[];
}
// The Crypto Market board for World's market dialog (mirrors main.ts's local `Market` type).
export interface WorldMarket {
  prices: { id: string; price: number; prev: number; flow?: number }[];
  holdings: { id: string; side: StockSide; shares: number; cost: number; worth: number; openedAt: number }[];
  history: { id: string; series: Record<StockTf, number[]> }[];
  nextUpdateAt: number;
}

// What the world needs from the rest of the app. main.ts supplies these (see startWorld call).
export interface WorldNet {
  enter(): void;                 // tell the server we're now in the world
  leave(): void;                 // tell the server we've left
  move(x: number, y: number, a?: number, car?: string | null, pet?: string | null, carColor?: string | null): void; // stream our state
  name(): string;                // our nickname (for our own label)
  color(): string;               // our avatar color
  needsCharacter(): boolean;      // true until a first-time visitor has confirmed a real name/color
  setCharacter(name: string, color: string): void; // confirm identity from World's own character creator
  selfId(): string;              // our connection id (to skip our own avatar in the broadcast)
  car(): string | null;          // our equipped car id (null = none → can't drive)
  boat(): string | null;         // our equipped boat id (null = none → can't board a boat)
  pet(): string | null;          // our equipped pet id (null = none → nothing trails us)
  carColor(): string | null;     // our equipped paint job overriding the car's stock colours (null = stock)
  // Shop — rendered natively inside World's own dialog (see openShop()) rather than delegated out
  // to the flat panel, so browsing/buying/equipping/spinning/betting never leaves World's view.
  wallet(): WorldWallet;
  shopBuy(item: string): void;
  shopEquip(slot: 'hat' | 'skin' | 'trail' | 'balltrail' | 'goalcelebr' | 'title' | 'song' | 'car' | 'boat' | 'pet' | 'carcolor', item: string | null): void;
  spinStatus(): { ready: boolean; label: string };
  dailySpin(): void;
  betInfo(): WorldBetInfo | null;
  adjustBetAmount(delta: number): void;
  setBetAmount(raw: number): void;
  placeBet(side: Side): void;
  // Bank sub-panels — also rendered natively inside World's own dialog (see openNews()/openLoan()/
  // openHouse()) rather than delegated out to the flat panels.
  newsFeed(): NewsItem[];
  newsReq(): void;
  loan(): { amount: number; owed: number; dueAt: number } | null;
  getLoan(amount: number): void;
  repayLoan(): void;
  houseState(): HouseStateMsg | null;
  houseReq(): void;
  bondBuy(amount: number, termDays: number): void;
  bondWithdraw(id: string): void;
  auctionBid(amount: number): void;
  // Crypto Market — also a native World dialog now (see openMarket()). The sell/cover modal is
  // reused as-is (openSellModal delegates straight to main.ts's existing implementation): it's
  // already a document.body-level overlay at z-index 100001, well above World's own dialog, so
  // there was nothing World-specific to rebuild there.
  market(): WorldMarket;
  stockInvest(coin: string, amount: number, side: StockSide): void;
  openSellModal(coinId: string, ticker: string, side: StockSide): void;
  // Slots — the first Casino cabinet with a native World dialog (see openSlots()). Unlike Shop/
  // Bank, Slots' flat-panel counterpart is a self-contained module (client/slots.ts) hardcoded
  // against fixed DOM ids, not exposed state — so World reimplements its (small) reel-spin
  // animation directly rather than reusing the module. playSound() reuses the flat game's actual
  // win/purchase audio clips instead of re-synthesizing them.
  slotsSpin(amount: number): void;
  playSound(sound: 'win' | 'cha'): void;
  // Craps — same reasoning/idiom as Slots above (client/craps.ts is a self-contained module).
  crapsRoll(pass: number, dontPass: number): void;
  // Blackjack — same reasoning (client/blackjack.ts).
  bjBet(amount: number): void;
  bjAction(action: 'hit' | 'stand' | 'double' | 'split'): void;
  // Hi-Lo — same reasoning (client/hilo.ts).
  hiloBet(amount: number): void;
  hiloGuess(guess: 'hi' | 'lo'): void;
  hiloCashout(): void;
  // Mines — same reasoning (client/mines.ts).
  minesBet(amount: number, mines: number): void;
  minesReveal(cell: number): void;
  minesCashout(): void;
  // Horse Racing — same reasoning (client/horse.ts).
  horseReq(): void;
  horseBet(horse: number, amount: number): void;
  // Crash — same reasoning (client/crash.ts). Unlike the others, crash state is a shared,
  // always-broadcasting spectacle (server pushes it every 100ms during a live round to every
  // connected client, not just requesters) — World caches the latest message so opening the
  // dialog mid-round shows current progress immediately, same as the flat panel does on open.
  crashBet(amount: number, autoCashout?: number): void;
  crashCancelBet(): void;
  crashCashout(): void;
  // Roulette — same reasoning (client/roulette.ts), the largest of the Casino cabinets (its own
  // betting board + wheel spin animation).
  rouletteSpin(bets: RouletteBet[]): void;
  // Plinko — same reasoning (client/plinko.ts), ports its canvas peg-drop physics directly.
  plinkoDrop(amount: number): void;
  // Notice Board sub-panels — also native World dialogs now (see openTourneyDialog()/
  // openSeasonDialog()/openPowerupsDialog()/openChangelogDialog()).
  tournament(): TournamentView | null;
  tournamentCreate(size: number): void;
  tournamentJoin(): void;
  tournamentCancel(): void;
  seasonPassReq(): void;
  seasonClaim(id: string): void;
  canSpawnPowerup(): boolean;
  spawnPowerup(kind: PowerupKind): void;
  // Lootbox / Marketplace — also native World dialogs now (see openLootDialog()/
  // openMarketplaceDialog()). `marketplace` is named distinctly from the Crypto Market's
  // `market()` above (different feature, same word in the flat UI's naming).
  lootBoxOpen(): void;
  marketplace(): MarketItemView[];
  marketplaceReq(): void;
  marketBuy(item: string): void;
  marketCancel(listingId: number): void;
  marketList(instanceId: number, ask: number): void;
  onExit(): void;                // the overlay closed (lets main.ts reset the toggle button)
  enterArena(): void;            // walk into the Arena → return to Pong + join the queue
  openFeature(feature: 'doom' | 'fishing' | 'campaign' | 'typedie' | 'racing' | 'superbros' | 'tron' | 'guitarhero' | 'artillery' | 'bowling' | 'nuketown' | 'citytycoon' | 'tnt' | 'monsterjam' | 'chess' | 'morris' | 'ski' | 'billiards' | 'frograce'): void; // open a DOOM/Fishing/Arcade/Bowling feature — every Casino game + Notice-Board panel is a native World dialog now
  openParliament(): void;        // walk into the Parliament → open the Nomic rules game overlay
  openRename(): void;            // World's own 👤 button → reopen the nickname/color picker
  muted(): boolean;              // is game sound currently muted?
  toggleMute(): void;            // flip the mute toggle (same pref/state as the toolbar's 🔊 button)
  leaderboard(): { name: string; wins: number; losses: number; elo: number; title?: string | null }[]; // live pong standings (pre-ranked)
  netWorth(): { name: string; net: number; coins: number; loan: number; title?: string | null }[];     // live net-worth board (pre-ranked)
  cortisolBoard(): { name: string; cortisol: number; title?: string | null }[];                        // live Cortisol board (pre-ranked low→high)
  levelBoard(): { name: string; xp: number; title?: string | null }[];                                  // live Levels board (pre-ranked by lifetime XP)
  // Our own rank + stat when we're NOT already in the visible top-N above (mirrors the toolbar
  // boards' pinned self-row) — null once we're already shown in leaderboard()/netWorth().
  selfLbRow(): { rank: number; elo: number } | null;
  selfNwRow(): { rank: number; net: number; loan: number } | null;
  selfCortisolRow(): { rank: number; cortisol: number } | null;
  // Report a stressful moment (a bad friend-sim interaction) so the server bumps our cortisol.
  stress(amount: number): void;
  // Usage-analytics breadcrumb: a client-side-only action worth counting (walking into a
  // building / interior room). The server namespaces + rate-limits it; fire-and-forget.
  track(name: string): void;
  eloProfileReq(rank?: number, self?: boolean): void;    // drill into a leaderboard row (index into leaderboard(), or self) → opens the real Elo profile modal
  balanceSheetReq(rank?: number, self?: boolean): void;  // drill into a net-worth row (index into netWorth(), or self) → opens the real balance-sheet modal
  claimQuest(quest: string): void; // tell the server to grant a World objective reward (once)
  dungeonSync(): void;             // entering the Ruins → ask which chests we've opened
  dungeonChest(chest: string, captured?: boolean): void; // open a chest ('B1:col,row') → server pays coins / grants prize (once). captured=true → a monster box caught (grant the pet)
  dungeonWin(floor: string, tier: number): void; // won an encounter → adds a TIER-ranged amount to the run purse
  dungeonTakeKey(): void; // took the key from the dying B3 adventurer (server marks the run-key)
  dungeonExit(escaped: boolean): void; // left the Ruins (escaped → server pays the run purse from the House)
  onNetizenClick?(netizenId: string): void; // user tapped a netizen avatar in the world (→ challenge)
  buyBeer(): void;               // buy a beer at the Tavern (server charges 20🪙 + ups drunk level)
  buyMcFood(item: string): void; // buy food at McDonald's (server charges coins + sends mcFoodResult)
  drunkLevel(): number;          // current drunkenness 0–6 (drives movement wobble + camera sway)
  stats(): { coins: number; elo: number | null; rank: number | null; fishLb: number }; // live wallet + pong rating + best catch (Mira reads these back to you)
  topPlayer(): { name: string; elo: number } | null;   // current #1 on the ELO board (the plaza statue)
  fishKing(): { name: string; lb: number } | null;     // biggest catch on record (billboard)
  ghKing(): { name: string; score: number } | null;    // top Tsong Hero score (billboard)
  wish(): void;                                        // toss 10 coins into the fountain
  mobHit(id: number, dmg: number): void;               // dealt damage to a shared server-owned mob (server resolves HP/death/bounty)
  worldBank(): void;                                   // reached town alive → bank the at-risk mob purse
  worldDied(): void;                                   // died in the wild → forfeit the unbanked purse
  owns(id: string): boolean;                           // do we own this cosmetic/item id? (wallet.owned)
  joinClub(): void;                                    // apply to the Country Club (server validates the 1,000,000🪙 fee)
  clubDrink(tier: number): void;                       // order off the 19th Hole's menu (server charges)
  // The Course — 2-4 player PvP rounds ride the same bg-relay room shape as chess/morris/ski
  // (game key 'golf'), just fed straight back into World instead of a lazy-loaded overlay, since
  // golf is played in-place on the grounds rather than in a teleported-away minigame.
  golfJoin(): void;
  golfLeave(): void;
  golfStake(stake: number): void;
  golfStart(): void;
  golfResult(winner: number): void;
  golfRelay(data: unknown): void;
  golfScore(strokes: number): void; // finished all 18 (solo or PvP) — server keeps your best for the course leaderboard
  jail(): void;                  // self-report a drunk-drive attempt (server jails you if 2+ beers in)
  bail(targetId: string): void;  // pay 500🪙 to bail a jailed avatar out (id; may be your own)
  amJailed(): boolean;           // are WE currently locked in the jail cell?
  dayNightOffset(): number;      // ms offset for the day/night clock (randomized per server boot)
  // --- Robville land ---
  landReq(): void;                          // ask the server for the current parcel book
  landBuyBank(id: string): void;            // buy an empty lot from the bank (PARCEL_PRICE)
  landList(id: string, ask: number): void;  // list your lot for sale at `ask` coins
  landUnlist(id: string): void;             // take your lot back off the market
  landBuy(id: string): void;                // buy a listed lot from its owner at the asking price
  houseBuild(id: string, house: string): void; // build a HOUSE_KINDS house on a lot you own
  houseDemolish(id: string): void;          // tear the house down on a lot you own (free)
  say(text: string, asSay?: boolean): void; // → speech bubble over your avatar (+ to others in-world); asSay=true → purple "Say" bubble
  boom(x: number, y: number, r?: number, fx?: WorldFx): void; // explosion here → broadcast to everyone else; r>0 = a damaging blast
  rocket(x: number, y: number, a: number, w?: WorldWeapon, len?: number): void; // we fired → broadcast so others watch the shot
  blownUp(car: boolean, self: boolean, killedBy?: string): void; // a blast got us (killedBy = shooter's pid for Road Rage)
  sendChat(text: string): void;             // → main game chat, so the line also shows in the side feed
  chatHistory(): ChatLine[];                // recent chat backlog, seeded (hidden) so it's there on T
  // Slash-command autocomplete, shared with the main chat (same COMMANDS list).
  worldChatMenu(text: string): { label: string; hint: string; complete: string; enabled: boolean }[];
  worldRunChatCommand(text: string): 'ran' | 'rejected' | 'passthrough';
}

// --- module-level controller so feedWorld()/isWorldOpen() can reach the live overlay ---
interface Controller {
  feed(avatars: WorldAvatar[]): void;
  feedLand(parcels: LandParcelView[], bankBought: number, bankCap: number): void; // Robville land book
  feedSay(id: string, name: string, text: string, say: boolean): void; // an in-world line → speech bubble (say=purple)
  feedBoom(x: number, y: number, r?: number, shooterPid?: string, fx?: WorldFx): void; // someone else's explosion → effect + blast; shooterPid for kill credit
  feedRocket(x: number, y: number, a: number, w?: WorldWeapon, len?: number): void; // someone else fired → render their shot
  feedChat(line: ChatLine): void; // a new chat line (mirrors the main chat into the side feed)
  feedRoadRage(active: boolean, endsAt: number, standings: { name: string; kills: number }[]): void;
  feedMcFood(item: string, granted: boolean, bonus?: number): void;
  reenter(): void; // re-send worldEnter after a socket reconnect (server forgot us on drop)
  dungeonChests(opened: string[]): void;                          // server's list of chests we've opened
  chestAccepted(chest: string, coins: number, potions: number, spin?: boolean, prize?: string, prizes?: string[]): void; // server accepted a chest open (prize/prizes = cosmetic names)
  dungeonSpinLoot(reward: { kind: 'coins'; amount: number } | { kind: 'item'; item: string; name: string }): void; // a spin chest's reward → run loot
  dungeonPurse(coins: number): void;                              // current run-purse total from the server
  feedEloProfile(msg: EloProfileMsg): void;         // server's answer to an eloProfileReq fired from the Hall of Fame
  feedBalanceSheet(msg: BalanceSheetMsg): void;     // server's answer to a balanceSheetReq fired from the Hall of Fame
  feedWallet(): void;                                // the wallet changed (buy/equip/spin settled) — re-render the shop dialog if it's open
  completeSkiObjective(): void;                       // a Frostreach ski race finished → mark the objective
  feedMobLoot(purse: number, gained?: number, banked?: number): void; // the at-risk mob-loot purse changed
  feedMobs(list: WorldMob[]): void;                    // server's authoritative mob roster → reconcile our sprites
  feedMobDead(id: number, x: number, y: number, kind: string, mine: boolean, potion: boolean): void; // a shared mob died → FX
  feedCortisol(): void;                               // the "Cortisol" board updated — refresh the top-bar cortisol gauge
  feedNews(): void;                                  // a new news item published — re-render the news dialog if it's open
  feedLoan(): void;                                  // the loan changed (taken/repaid/collected/countdown tick) — re-render the loan dialog if it's open
  feedHouse(): void;                                 // the Fed dashboard changed (bond/auction/tax update) — re-render the house dialog if it's open
  feedMarket(): void;                                // prices/holdings re-rolled — re-render the market dialog if it's open
  feedSlotsResult(msg: SlotsResultMsg): void;        // a spin settled — animate it if the slots dialog is open
  feedCrapsResult(msg: CrapsResultMsg): void;        // a roll settled — update it if the craps dialog is open
  feedBjState(msg: BjStateMsg): void;
  feedBjResult(msg: BjResultMsg): void;
  feedHiloState(msg: HiLoStateMsg): void;
  feedHiloResult(msg: HiLoResultMsg): void;
  feedMinesState(msg: MinesStateMsg): void;
  feedMinesResult(msg: MinesResultMsg): void;
  feedHorseCard(msg: HorseCardMsg): void;
  feedHorseResult(msg: HorseResultMsg): void;
  feedCrashState(msg: CrashStateMsg): void;
  feedRouletteResult(msg: { number: number; staked: number; payout: number }): void;
  feedPlinkoResult(msg: PlinkoResultMsg): void;
  feedSeasonPass(weekId: string, challenges: SeasonChallenge[]): void;
  feedLootResult(msg: LootResultMsg): void;
  feedMarketplace(items: MarketItemView[]): void;
}
let controller: Controller | null = null;
let _exitWorld: (() => void) | null = null;
let _pauseWorld: (() => void) | null = null;
let _resumeWorld: (() => void) | null = null;

export function isWorldOpen(): boolean {
  return controller !== null;
}

/** A Frostreach ski race finished → complete the ski objective (once). No-op if World is closed. */
export function completeSkiObjective(): void {
  controller?.completeSkiObjective();
}

/** Tear down the world overlay if it's open. No-op if already closed. */
export function exitWorld(): void {
  _exitWorld?.();
}

/** Hide + freeze World (it stays alive underneath) while a delegated panel/minigame is up. */
export function pauseWorld(): void {
  _pauseWorld?.();
}
/** Bring a paused World back — same position, same everything. No-op if World isn't paused. */
export function resumeWorld(): void {
  _resumeWorld?.();
}

/** Push the latest avatar roster (from a `world` server message) into the live overlay. */
export function feedWorld(avatars: WorldAvatar[]): void {
  controller?.feed(avatars);
}

/** The server's list of dungeon chests this player has already opened (reply to dungeonSync). */
export function feedDungeonChests(opened: string[]): void {
  controller?.dungeonChests(opened);
}

/** The wallet changed (buy/equip/daily-spin settled) — re-render the shop dialog if it's open. */
export function feedWallet(): void {
  controller?.feedWallet();
}

/** The server-held at-risk mob-loot purse changed (a kill added to it, or it banked/forfeited). */
export function feedMobLoot(purse: number, gained?: number, banked?: number): void {
  controller?.feedMobLoot(purse, gained, banked);
}

/** The server's authoritative shared-mob roster (a `worldMobs` broadcast) → reconcile our sprites. */
export function feedMobs(list: WorldMob[]): void {
  controller?.feedMobs(list);
}

/** A shared mob died (`mobDead`) → play the death FX for everyone; `mine` = we landed the kill. */
export function feedMobDead(id: number, x: number, y: number, kind: string, mine: boolean, potion: boolean): void {
  controller?.feedMobDead(id, x, y, kind, mine, potion);
}

/** The "Cortisol" board updated — refresh the World top-bar cortisol gauge. */
export function feedCortisol(): void {
  controller?.feedCortisol();
}

/** A new news item published — re-render the news dialog if it's open. */
export function feedNews(): void {
  controller?.feedNews();
}

/** The loan changed (taken/repaid/collected/countdown tick) — re-render the loan dialog if it's open. */
export function feedLoan(): void {
  controller?.feedLoan();
}

/** The Fed dashboard changed (bond/auction/tax update) — re-render the house dialog if it's open. */
export function feedHouse(): void {
  controller?.feedHouse();
}

/** Prices/holdings re-rolled — re-render the market dialog if it's open. */
export function feedMarket(): void {
  controller?.feedMarket();
}

/** A slots spin settled — animate it if the slots dialog is open. */
export function feedSlotsResult(msg: SlotsResultMsg): void {
  controller?.feedSlotsResult(msg);
}

/** A craps roll settled — update it if the craps dialog is open. */
export function feedCrapsResult(msg: CrapsResultMsg): void {
  controller?.feedCrapsResult(msg);
}
export function feedBjState(msg: BjStateMsg): void { controller?.feedBjState(msg); }
export function feedBjResult(msg: BjResultMsg): void { controller?.feedBjResult(msg); }
export function feedHiloState(msg: HiLoStateMsg): void { controller?.feedHiloState(msg); }
export function feedHiloResult(msg: HiLoResultMsg): void { controller?.feedHiloResult(msg); }
export function feedMinesState(msg: MinesStateMsg): void { controller?.feedMinesState(msg); }
export function feedMinesResult(msg: MinesResultMsg): void { controller?.feedMinesResult(msg); }
export function feedHorseCard(msg: HorseCardMsg): void { controller?.feedHorseCard(msg); }
export function feedHorseResult(msg: HorseResultMsg): void { controller?.feedHorseResult(msg); }
export function feedCrashState(msg: CrashStateMsg): void { controller?.feedCrashState(msg); }
export function feedRouletteResult(msg: { number: number; staked: number; payout: number }): void { controller?.feedRouletteResult(msg); }
export function feedPlinkoResult(msg: PlinkoResultMsg): void { controller?.feedPlinkoResult(msg); }
export function feedSeasonPass(weekId: string, challenges: SeasonChallenge[]): void { controller?.feedSeasonPass(weekId, challenges); }
export function feedLootResult(msg: LootResultMsg): void { controller?.feedLootResult(msg); }
export function feedMarketplace(items: MarketItemView[]): void { controller?.feedMarketplace(items); }

/** The server accepted a chest open (added the coins to the run purse / granted the potion). */
export function dungeonChestAccepted(chest: string, coins: number, potions: number, spin?: boolean, prize?: string, prizes?: string[]): void {
  controller?.chestAccepted(chest, coins, potions, spin, prize, prizes);
}
export function dungeonSpinLoot(reward: { kind: 'coins'; amount: number } | { kind: 'item'; item: string; name: string }): void {
  controller?.dungeonSpinLoot(reward);
}

/** The current run-purse total (paid out only when you escape the Ruins). */
export function feedDungeonPurse(coins: number): void {
  controller?.dungeonPurse(coins);
}

/** Push the latest Robville land book (from a `land` server message) into the live overlay. */
export function feedLand(parcels: LandParcelView[], bankBought: number, bankCap: number): void {
  controller?.feedLand(parcels, bankBought, bankCap);
}

/** Pop a speech bubble over a world avatar (from a `worldSay` server message). */
export function feedSay(id: string, name: string, text: string, say = false): void {
  controller?.feedSay(id, name, text, say);
}

/** Render an explosion at a world point (from a `worldBoom` server message). No-op if closed. */
export function feedBoom(x: number, y: number, r?: number, shooterPid?: string, fx?: WorldFx): void {
  controller?.feedBoom(x, y, r, shooterPid, fx);
}

/** Render another player's shot streaking across the world (from a `worldRocket` message). */
export function feedRocket(x: number, y: number, a: number, w?: WorldWeapon, len?: number): void {
  controller?.feedRocket(x, y, a, w, len);
}

/** Mirror a chat line (from a `chat` server message) into the in-world side feed. No-op if closed. */
export function feedWorldChat(line: ChatLine): void {
  controller?.feedChat(line);
}

/** Re-assert our presence in the world after a reconnect (the server drops us on socket close). */
export function reenterWorld(): void {
  controller?.reenter();
}

/** Handle a Road Rage event broadcast. */
export function feedRoadRage(active: boolean, endsAt: number, standings: { name: string; kills: number }[]): void {
  controller?.feedRoadRage(active, endsAt, standings);
}

/** Handle a McDonald's food result from the server. */
export function feedMcFood(item: string, granted: boolean, bonus?: number): void {
  controller?.feedMcFood(item, granted, bonus);
}

/** Server's answer to an eloProfileReq fired from inside the Hall of Fame. No-op if World is closed. */
export function feedEloProfile(msg: EloProfileMsg): void {
  controller?.feedEloProfile(msg);
}
/** Server's answer to a balanceSheetReq fired from inside the Hall of Fame. No-op if World is closed. */
export function feedBalanceSheet(msg: BalanceSheetMsg): void {
  controller?.feedBalanceSheet(msg);
}

