      px2(2, 5, 3, 4, F2);                                      // haunch (rear, left)
      px2(1, 4, 2, 3, F); px2(0, 3, 1, 2, DK);                 // tail up
      px2(15, 4, 5, 5, F); px2(19, 6, 2, 3, F2);               // head + snout (right)
      px2(20, 7, 1, 2, MAW);                                    // muzzle tip
